// Récupérer les items (peut être vide)
const items = $input.all();

// Si aucun item, retourner une réponse vide mais valide
if (!items || items.length === 0 || !items[0].json || Object.keys(items[0].json).length === 0) {
  return [{
    json: {
      success: true,
      timestamp: new Date().toISOString(),
      message: "Aucun fichier trouvé dans Google Drive",
      statistiques: {
        totalDossiers: 0,
        totalFichiers: 0
      },
      elements: {
        dossiers: [],
        fichiers: []
      }
    }
  }];
}

// Séparer dossiers et fichiers
const dossiers = [];
const fichiers = [];

for (const item of items) {
  const data = item.json;

  // Vérifier que l'item a des données
  if (!data || !data.id) continue;

  if (data.mimeType === 'application/vnd.google-apps.folder') {
    dossiers.push({
      id: data.id,
      nom: data.name || 'Sans nom',
      type: 'dossier',
      mimeType: data.mimeType
    });
  } else {
    fichiers.push({
      id: data.id,
      nom: data.name || 'Sans nom',
      type: 'fichier',
      mimeType: data.mimeType || 'unknown'
    });
  }
}

// Construire la réponse
return [{
  json: {
    success: true,
    timestamp: new Date().toISOString(),
    statistiques: {
      totalDossiers: dossiers.length,
      totalFichiers: fichiers.length,
      totalElements: dossiers.length + fichiers.length
    },
    elements: {
      dossiers: dossiers,
      fichiers: fichiers
    }
  }
}];
